const scriptPacket = $json.final_script_packet || { payload: { target_platform: 'generic', metadata: {} } };
const platforms = { youtube: { tools: ['video_editor', 'subtitle_generator'], constraints: ['max_length_4h', 'quality_1080p_min'] }, blog: { tools: ['markdown_renderer', 'image_optimizer'], constraints: ['plain_text_only', 'no_video'] }, podcast: { tools: ['audio_optimizer', 'transcript_generator'], constraints: ['audio_only', 'max_bitrate_192kbps'] }, email: { tools: ['html_renderer', 'link_tracker'], constraints: ['plain_text_fallback', 'max_width_600px'] } };
const platform = scriptPacket.payload?.target_platform || 'generic';
const allowedTools = platforms[platform]?.tools || ['generic_renderer'];
const constraints = platforms[platform]?.constraints || ['generic_constraints'];
const contextEnvelope = { instance_id: 'CTX-' + Date.now(), platform: platform, allowed_tools: allowedTools, forbidden_tools: ['shell_execution', 'external_api_call_untracked'], execution_constraints: constraints, quality_gates: { min_coherence: 0.85, min_accuracy: 0.90 } };
return [{ json: { ...$json, context_envelope: contextEnvelope, execution_context_built: true } }];

const packet = {
  instance_id: $json.context_envelope.instance_id,
  artifact_family: 'execution_context_packet',
  schema_version: '1.0.0',
  producer_workflow: 'CWF-310',
  dossier_ref: $json.dossier_id || 'DOSSIER-UNSPECIFIED',
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    execution_context_built: true,
    target_platform: $json.context_envelope.platform,
    allowed_tools: $json.context_envelope.allowed_tools,
    forbidden_tools: $json.context_envelope.forbidden_tools,
    execution_constraints: $json.context_envelope.execution_constraints,
    quality_gates: $json.context_envelope.quality_gates
  }
};
return [{ json: { ...$json, execution_context_packet: packet, packet_emitted: true } }];

try {
  const workflowId = 'CWF-310';
  const defaultSkillMap = {
    'CWF-610': 'M-185',
    'CWF-620': 'M-200',
    'CWF-630': 'M-215'
  };
  const skillId = $json.skill_id || defaultSkillMap[workflowId] || 'M-001';
  const dossierId = $json.body?.dossier_id || $json.dossier_context?.dossier_id || $json.dossier_id || 'DOSSIER-UNSPECIFIED';

  const payload = {
    dossier_id: dossierId,
    dossier_ref: dossierId,
    workflow_id: workflowId,
    workflow_ref: workflowId,
    skill_id: skillId,
    source_node: 'Skill Execution Node',
    route_id: $json.body?.route_id || $json.route_id || $json.dossier_context?.route || null,
    task: $json.body?.topic || $json.body?.user_message || $json.body?.message || $json.topic || $json.user_message || $json.message || (($json.body?.mission_context || $json.mission_context) && (($json.body?.mission_context || $json.mission_context).normalized_topic || ($json.body?.mission_context || $json.mission_context).original_user_message)) || 'MISSION_CONTEXT_MISSING',
    context: {
      topic: $json.body?.topic || $json.body?.user_message || $json.body?.message || $json.topic || $json.user_message || $json.message || (($json.body?.mission_context || $json.mission_context) && (($json.body?.mission_context || $json.mission_context).normalized_topic || ($json.body?.mission_context || $json.mission_context).original_user_message)) || null,
      mode: $json.body?.user_mode || $json.user_mode || $json.mode || 'creator', mission_context: $json.body?.mission_context || $json.mission_context || null
    },
    dossier: typeof $json.dossier === 'object' ? $json.dossier : {}
  };

  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://127.0.0.1:5002/operator/skill-runtime',
    headers: { 'content-type': 'application/json' },
    body: payload,
    json: true,
    timeout: 120000
  });
  if (result.status !== 'SUCCESS' || !result.runtime_packet) {
    throw new Error(String(result.error || 'skill-runtime returned no runtime_packet'));
  }

  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: workflowId,
        skill_id: skillId,
        status: 'SUCCESS',
        had_error: false,
        error_message: '',
        timestamp: new Date().toISOString()
      },
      runtime_packet: result.runtime_packet,
      skill_execution_result: result.skill_execution_result || result,
      runtime: { had_error: false, error_message: '' }
    }
  }];
} catch (error) {
  const message = String(error && error.message ? error.message : error);
  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: 'CWF-310',
        skill_id: $json.skill_id || null,
        status: 'ERROR',
        had_error: true,
        error_message: message,
        timestamp: new Date().toISOString()
      },
      runtime_packet: null,
      skill_execution_result: null,
      runtime: { had_error: true, error_message: message }
    }
  }];
}
